<template>
  <div>
    <el-breadcrumb separator="/" style="padding-left: 10px;padding-bottom: 10px;font-size: 12px">
      <el-breadcrumb-item :to="{ path: '/main' }">首页</el-breadcrumb-item>
      <el-breadcrumb-item>系统管理</el-breadcrumb-item>
      <el-breadcrumb-item>三方协议书审核</el-breadcrumb-item>
    </el-breadcrumb>

    <el-card class="box-card">
      <el-form :inline="true" :model="dataVo" class="demo-form-inline">
        <el-form-item label="简历名称" label-width="70px">
          <el-input clearable v-model="dataVo.rtitle" placeholder="请输入简历名称"></el-input>
        </el-form-item>
        <el-form-item label="岗位名称" label-width="70px">
          <el-input clearable v-model="dataVo.rname" placeholder="请输入岗位名称"></el-input>
        </el-form-item>
        <el-form-item label="学生姓名" label-width="70px">
          <el-input clearable v-model="dataVo.sname" placeholder="请输入学生姓名"></el-input>
        </el-form-item>
        <el-form-item label="简历类型" label-width="70px">
          <el-input clearable v-model="dataVo.tname" placeholder="请输入简历类型"></el-input>
        </el-form-item>
        <el-form-item label="专业名称" label-width="70px">
          <el-input clearable v-model="dataVo.smajor" placeholder="请输入专业名称"></el-input>
        </el-form-item>
        <el-form-item label="学院名称" label-width="70px">
          <el-input clearable v-model="dataVo.scollege" placeholder="请输入学院名称"></el-input>
        </el-form-item>
        <el-form-item style="margin-left: 10px">
          <el-button icon="el-icon-refresh" @click="resetDataVo">重置</el-button>
          <el-button type="primary" icon="el-icon-search" @click="getDataList">查询</el-button>
        </el-form-item>
      </el-form>
      <el-table
        :data="dataList"
        border
        max-height="400"
        style="width: 100%;">
        <el-table-column
          prop="id"
          label="#"
          type="index"
          width="50">
        </el-table-column>
        <el-table-column
          prop="rtitle"
          label="简历名称"
          width="150">
        </el-table-column>
        <el-table-column
          prop="rname"
          label="岗位名称"
          width="150">
        </el-table-column>
        <el-table-column
          sortable
          prop="rdate"
          label="添加日期"
          width="100">
          <template slot-scope="scope">
            {{scope.row.rdate}}
          </template>
        </el-table-column>
        <el-table-column
          prop="sname"
          label="学生姓名"
          width="130">
        </el-table-column>
        <el-table-column
          prop="stel"
          label="学生电话"
          width="100">
        </el-table-column>
        <el-table-column
          prop="smajor"
          label="所在专业"
          width="150">
        </el-table-column>
        <el-table-column
          prop="scollege"
          label="所在学院"
          width="180">
        </el-table-column>
        <el-table-column
          prop="sclass"
          label="所在班级"
          width="160">
        </el-table-column>
        <el-table-column
          sortable
          prop="tname"
          label="简历类型"
          width="180">
        </el-table-column>
        <el-table-column
          sortable
          prop="astuts"
          label="应聘状态"
          width="180">
        </el-table-column>
        <el-table-column
          label="操作" width="210">
          <template slot-scope="scope">
            <el-button type="danger" size="mini" icon="el-icon-delete"
                       @click="deleteDatas(scope.row.id)" title="删除"></el-button>
            <el-button type="danger" size="mini" v-if="scope.row.aflag == 6" icon="el-icon-delete"
                       @click="auditsignDatas(scope.row.id)" title="审核通过"></el-button>
            <el-button type="danger" size="mini" v-if="scope.row.aflag == 6" icon="el-icon-delete"
                       @click="noauditsignDatas(scope.row.id)" title="审核不通过"></el-button>
          </template>
        </el-table-column>
      </el-table>
      <el-pagination
        style="padding-top: 15px"
        @size-change="handleSizeChange"
        @current-change="handleCurrentChange"
        :current-page="current"
        :page-sizes="[6, 10, 20, 30]"
        :page-size="size"
        layout="total, sizes, prev, pager, next, jumper"
        :total="total">
      </el-pagination>
    </el-card>
  </div>

</template>

<script>
  import { findAdminApplysDatasForUserList,
    deleteAdminApplysDatas,passApplys,nopassApplys,signagreementDatas,adminauditsignDatas, adminnoauditsignDatas } from '../../api/resumes';

  export default {
    name: 'MyApplys2',
    data() {
      return {
        dataVo: {
          rtitle:'',
          rname:'',
          sname:'',
          tname:'',
          smajor:'',
          scollege:''
        },
        addOrUpdateVisible: false,
        editOrUpdateVisible: false,
        dataList: [],
        size: 6,
        total: 100,
        current: 1
      };
    },
    components: {
    },
    created(){
      this.getDataList();
    },
    methods: {
      onSubmit() {
      },
      handleSizeChange(val) {
        this.size = val;
        this.getDataList();
      },
      handleCurrentChange(val) {
        this.current = val;
        this.getDataList();
      },
      async getDataList(){
        if(this.$session.get("phone") == null)
          this.$router.push("/login");
        const { data } = await findAdminApplysDatasForUserList(this.current,this.size,this.dataVo,this.$session.get("phone"));
        this.dataList = data.data.records;
        this.total = data.data.total;
      },
      resetDataVo(){
        this.dataVo.rtitle = '';
        this.dataVo.rname = '';
        this.dataVo.sname = '';
        this.dataVo.stel = '';
        this.dataVo.smajor = '';
        this.dataVo.scollege = '';
        this.dataVo.tname = '';
        this.getDataList();
      },
      show(){
        this.addOrUpdateVisible = true;
      },
      auditsignDatas(id){
        var that = this;
        this.$confirm('此操作将审核通过, 是否继续?', '提示', {
          confirmButtonText: '确定',
          cancelButtonText: '取消',
          type: 'warning'
        }).then(() => {
          adminauditsignDatas(id);
          this.$message({
            type: 'success',
            message: '邀请发出成功!'
          });
          that.getDataList();
        }).catch(() => {
          this.$message({
            type: 'info',
            message: '邀请发出失败'
          });
        });
      },
      noauditsignDatas(id){
        var that = this;
        this.$confirm('此操作将审核不通过, 是否继续?', '提示', {
          confirmButtonText: '确定',
          cancelButtonText: '取消',
          type: 'warning'
        }).then(() => {
          adminnoauditsignDatas(id);
          this.$message({
            type: 'success',
            message: '邀请发出成功!'
          });
          that.getDataList();
        }).catch(() => {
          this.$message({
            type: 'info',
            message: '邀请发出失败'
          });
        });
      },
      deleteDatas(id){
        var that = this;
        this.$confirm('此操作将删除应聘信息, 是否继续?', '提示', {
          confirmButtonText: '确定',
          cancelButtonText: '取消',
          type: 'warning'
        }).then(() => {
          deleteAdminApplysDatas(id);
          this.$message({
            type: 'success',
            message: '取消应聘成功!'
          });
          that.getDataList();
        }).catch(() => {
          this.$message({
            type: 'info',
            message: '已取消删除'
          });
        });
      },
       dataEdit(row){
        var that = this;
         this.editOrUpdateVisible = true;
        this.$nextTick(() => {
            that.$refs.eidtOrUpdateRef.dataInit(row);
        });
         this.getDataList();
        console.log(this.dataEdit);
      },
      showAddOrUpdate(data){
        if(data === 'false'){
          this.addOrUpdateVisible = false;
        }else{
          this.addOrUpdateVisible = true;
        }
        this.getDataList();
      },
      showEidtOrUpdate(data){
        if(data === 'false'){
          this.editOrUpdateVisible = false;
        }else{
          this.editOrUpdateVisible = true;
        }
        this.getDataList();
      }
    }
  };
</script>

<style scoped>

</style>
